// Map each email into one Aninaya inbound item and stash it in
// workflow static data (the zero-dependency 'inbox'). Tune the
// amount/merchant parsing to your bills.
const staticData = $getWorkflowStaticData('global');
staticData.items = staticData.items ?? [];

for (const item of $input.all()) {
  const subject = item.json.subject ?? '';
  const snippet = item.json.snippet ?? '';
  const text = `${subject} ${snippet}`;
  // First peso-looking number, e.g. 1,299.50 or P1299.50.
  const m = text.match(/(?:PHP|P|\u20B1)?\s?([0-9][0-9,]*\.?[0-9]{0,2})/);
  if (!m) continue;
  const amount = Number(m[1].replace(/,/g, ''));
  if (!amount || Number.isNaN(amount)) continue;

  const entry = {
    id: item.json.id,                       // Gmail message id = dedup key
    source: 'n8n:gmail-bills',
    type: 'outflow',
    amount,
    merchant: (item.json.from?.value?.[0]?.name) || subject.slice(0, 40) || 'Unknown',
    title: subject.slice(0, 80),
    notes: 'Parsed from Gmail via n8n',
    created_at: item.json.date || new Date().toISOString(),
  };
  // Idempotent append — Aninaya dedups too, but keep the inbox tidy.
  if (!staticData.items.some((x) => x.id === entry.id)) {
    staticData.items.push(entry);
  }
}
// Cap the inbox at the 100 most recent items.
staticData.items = staticData.items.slice(-100);
return [{ json: { stored: staticData.items.length } }];

// Verify the shared secret Aninaya sends on every poll, then answer
// with the accumulated items in the documented contract shape.
const SECRET = 'CHANGE-ME'; // must match Aninaya Settings → Integrations
const headers = $input.first().json.headers ?? {};
const got = headers['x-kaiju-webhook-secret'];
if (!got || got !== SECRET) {
  // Never echo the expected secret in the response.
  return [{ json: { error: 'unauthorized' }, pairedItem: 0 }];
}
const staticData = $getWorkflowStaticData('global');
return [{ json: { schema_version: '1', items: staticData.items ?? [] } }];
